                board[r][c]=(board[r][c]+d)%MOD
    elif op=='shift_row':
        r=e['row']; a=e['amount']%N; row=board[r][:]
        for c in range(N): board[r][(c+a)%N]=row[c]
    elif op=='shift_col':
        c=e['col']; a=e['amount']%N; col=[board[r][c] for r in range(N)]
        for r in range(N): board[(r+a)%N][c]=col[r]
    elif op=='rotate':
        t=e['top']; l=e['left']; s=e['size']; turns=e['turns']%4
        for _ in range(turns):
            old=[row[:] for row in board]
            for i in range(s):
                for j in range(s): board[t+j][l+s-1-i]=old[t+i][l+j]
    elif op=='swap':
        a=e['first']; b=e['second']
        for r in range(N):
            for c in range(N):
                if board[r][c]==a: board[r][c]=b
                elif board[r][c]==b: board[r][c]=a
    else:
        raise ValueError(op)

def enc(board):
    s=0; bit=0
    for r in range(4):
        for c in range(4):
            s |= board[r][c] << bit
            bit += 2
    return s

def dec(s):
    b=[[0]*4 for _ in range(4)]
    for i in range(16):
        b[i//4][i%4]=(s>>(2*i))&3
    return b

@lru_cache(maxsize=None)
def act(s, op):
    vals=[(s>>(2*i))&3 for i in range(16)]
    out=vals[:]
    kind, idx = op[0], int(op[1])
    if kind=='R':
        base=4*idx; row=vals[base:base+4]
        for c in range(4): out[base+((c+1)&3)] = (row[c]+1)&3
    elif kind=='L':
        base=4*idx; row=vals[base:base+4]
        for c in range(4): out[base+c] = (row[(c+1)&3]-1)&3
    elif kind=='D':
        c=idx; col=[vals[r*4+c] for r in range(4)]
        for r in range(4): out[((r+1)&3)*4+c] = (col[r]+1)&3
    elif kind=='U':
        c=idx; col=[vals[r*4+c] for r in range(4)]
        for r in range(4): out[r*4+c] = (col[(r+1)&3]-1)&3
    t=0
    for i,v in enumerate(out): t |= v << (2*i)
    return t

# exact layers from zero up to depth 5
layers=[{0}]
seen={0}
for depth in range(1,6):
    nxt=set()
    for s in layers[-1]:
        for op in ops:
            t=act(s,op)
            if t not in seen:
                seen.add(t)
                nxt.add(t)
    layers.append(nxt)

# suffix reconstruction for states known to be at exact distance k<=5 from zero
@lru_cache(maxsize=None)
def suffix_to_zero(s, k):
    if k==0:
        assert s==0
        return []
    for op in ops:
        t=act(s, op)
        if t in layers[k-1]:
            return [op] + suffix_to_zero(t, k-1)
    raise RuntimeError(('no suffix', s, k))

def find_solution(target):
    from functools import lru_cache
    for D in range(10):
        max_prefix=min(4,D)
        @lru_cache(maxsize=None)
        def dfs(s, used):
            rem=D-used
            if rem<=5 and s in layers[rem]:
                return suffix_to_zero(s, rem)
            if used==max_prefix:
                return None
            # if even after using all prefix moves we can't get rem<=5, prune
            if D-(used+ (max_prefix-used)) > 5:
                return None
            for op in ops:
                t=act(s, op)
                rest=dfs(t, used+1)
                if rest is not None:
                    return [op] + rest
            return None
        ans=dfs(target,0)
        if ans is not None:
            return ans
    raise RuntimeError('no solution <=9')

def apply_action_state(s, op):
    return act(s, op)

